package re.manager.repository;

import org.springframework.stereotype.Repository;
import re.manager.model.entity.Equipment;

import java.util.ArrayList;
import java.util.List;

@Repository
public class EquipmentRepository {

    private final List<Equipment> equipmentList = new ArrayList<>();
    private Long idCounter = 1L;

    public EquipmentRepository() {

        // data mẫu
        equipmentList.add(new Equipment(idCounter++, "Màn hình Dell", "Full HD", 10, "data:image/webp;base64,","DEVICE"));
        equipmentList.add(new Equipment(idCounter++, "Bàn phím cơ", "RGB", 5, "https://laptop88.vn/media/news/2806_cau-tao-ban-phim-co.jpg","DEVICE"));
        equipmentList.add(new Equipment(idCounter++, "Phòng 1", "Phòng rộng lắm", 1, "https://laptop88.vn/media/news/2806_cau-tao-ban-phim-co.jpg","LAB"));
        equipmentList.add(new Equipment(idCounter++, "Raspberry Pi", "Board mạch", 3, "data:image/jpeg;base64,","DEVICE"));
    }

    // 🔍 lấy tất cả
    public List<Equipment> findAll() {
        return equipmentList;
    }

    // 🔍 tìm theo id
    public Equipment findById(Long id) {
        return equipmentList.stream()
                .filter(e -> e.getId().equals(id))
                .findFirst()
                .orElse(null);
    }

    // ➕ thêm mới
    public void save(Equipment e) {
        e.setId(idCounter++);
        equipmentList.add(e);
    }

    // ✏️ cập nhật
    public void update(Equipment updated) {
        for (Equipment e : equipmentList) {
            if (e.getId().equals(updated.getId())) {
                e.setName(updated.getName());
                e.setDescription(updated.getDescription());
                e.setQuantity(updated.getQuantity());
                e.setImageUrl(updated.getImageUrl());
                break;
            }
        }
    }

    // ❌ xóa
    public void delete(Long id) {
        equipmentList.removeIf(e -> e.getId().equals(id));
    }
}